                -- MemoryVariable(1422, <b_asic.port.OutputPort object at 0x7f510d51c9f0>, {<b_asic.port.InputPort object at 0x7f510d52e190>: 117}, 'mads48.0')
                when "11000000001" =>
                    read_adr_0_0_0 <= to_unsigned(20, read_adr_0_0_0'length);
                    read_en_0_0_0 <= '1';
                -- FIX
                when "11000000010" =>
                    read_adr_0_0_0 <= to_unsigned(5, read_adr_0_0_0'length);
                    read_en_0_0_0 <= '1';
                when others =>
                    read_adr_0_0_0 <= (others => '-');
                    read_en_0_0_0 <= '0';
            end case;
    end process mem_read_address_proc;

end architecture rtl;

